        public Card.Cards HandlePickDecision(Card.Cards originCard, List<Card.Cards> choices, Board board)
        {
            try
            {
                Log(string.Format("Trying offline HSReplay discover for {0} in {1} mode ...",
                    CardTemplate.LoadFromId(originCard).Name, Bot.CurrentMode()));

                // Get origin card's dbf_id
                int originDbfId = CardTemplate.LoadFromId(originCard).DbfId;

                // Select data based on mode
                bool isStandard = Bot.CurrentMode() == Bot.Mode.Standard ||
                                  Bot.CurrentMode() == Bot.Mode.Casual ||
                                  Bot.CurrentMode() == Bot.Mode.Practice;

                var discoverData = isStandard ? StandardDiscoverData : WildDiscoverData;

                // Look up choices for this origin card
                if (!discoverData.ContainsKey(originDbfId))
                {
                    Log("No offline discover data for this card, falling back.");
                    return Card.Cards.CRED_01;
                }

                var hsChoices = discoverData[originDbfId];
                Log(string.Format("Found {0} discover entries for card dbf_id {1}", hsChoices.Count, originDbfId));

                return FindBestPick(hsChoices, choices);
            }
            catch (Exception e)
            {
                Log(e.ToString());
                return Card.Cards.CRED_01;
            }
        }

        private Card.Cards FindBestPick(List<DiscoverChoice> hsChoices, List<Card.Cards> choices)
        {
            Dictionary<Card.Cards, float> values = new Dictionary<Card.Cards, float>();

            foreach (var choice in choices)
            {
                if (!values.ContainsKey(choice))
                {
                    int choiceDbfId = CardTemplate.LoadFromId(choice).DbfId;
                    var entry = hsChoices.FirstOrDefault(x => x.DbfId == choiceDbfId);

                    if (entry != null)
                    {
                        float value = entry.Popularity * entry.Winrate;
                        Log(string.Format("Choice : {0} - Pop: {1} - WR: {2} - Value: {3}",
                            CardTemplate.LoadFromId(choice).Name,
                            entry.Popularity.ToString("F2"),
                            entry.Winrate.ToString("F2"),
                            value.ToString("F2")));
                        values.Add(choice, value);
                    }
                    else
                    {
                        Log(string.Format("Choice [{0}] has no HSReplay data", CardTemplate.LoadFromId(choice).Name));
                    }
                }
            }

            if (values.Count == 0)
            {
                throw new Exception("None of the choices had an entry in offline HSReplay data, falling back to default logic ...");
            }

            var maxValue = values.Values.Max();
            var bestChoice = values.FirstOrDefault(x => x.Value == maxValue).Key;
            Log(string.Format("Best choice : {0} - {1}",
                CardTemplate.LoadFromId(bestChoice).Name,
                values[bestChoice].ToString("F2")));
            return bestChoice;
        }

        private void Log(string log)
        {
            Bot.Log("[HSReplayDiscoverOffline] " + log);
        }

        #endregion
    }
}
